final:
module top_module(
    input x,
    input y,
    output z
);
    assign z = ~(x & y);
endmodule

module H(
    input x,
    input y,
    output z
);
    assign z = 1;
endmodule

module top_module(
    input x,
    input y,
    output z
);
    wire g1_out, g2_out, h1_out, h2_out;
    wire xor_out, and_out;

    G g1(.x(x), .y(y), .z(g1_out));
    G g2(.x(x), .y(y), .z(g2_out));
    H h1(.x(x), .y(y), .z(h1_out));
    H h2(.x(x), .y(y), .z(h2_out));

    assign xor_out = g1_out ^ h1_out;
    assign and_out = g2_out & h2_out;

    assign z = xor_out | and_out;
endmodule
